/**
 * @param {number} n
 * @param {number[][]} edges
 * @param {number} k
 * @return {number}
 */
function solve(n, edges, k) {
    // Sort edges by weight in ascending order
    edges.sort((a, b) => a[2] - b[2]);

    // Initialize Union-Find structure
    const uf = new UnionFind(n);

    // Track the maximum cost of each component
    const maxCost = new Array(n).fill(0);

    // Process edges in order of increasing weight
    for (const [u, v, w] of edges) {
        // Check if u and v are already in the same component
        if (uf.find(u) !== uf.find(v)) {
            // Merge the components
            uf.union(u, v);
            // Update the max cost of the new component
            maxCost[uf.find(u)] = Math.max(maxCost[uf.find(u)], w);
        }
    }

    // Find the k-th largest max cost
    // Sort the maxCost array and take the k-th largest
    const sortedMaxCost = [...maxCost].sort((a, b) => b - a);
    return sortedMaxCost[k - 1];
}

// Union-Find data structure
class UnionFind {
    constructor(n) {
        this.parent = Array(n).fill(0).map((_, i) => i);
        this.rank = Array(n).fill(0);
    }

    find(x) {
        if (this.parent[x] !== x) {
            this.parent[x] = this.find(this.parent[x]);
        }
        return this.parent[x];
    }

    union(x, y) {
        const xRoot = this.find(x);
        const yRoot = this.find(y);

        if (xRoot === yRoot) return;

        if (this.rank[xRoot] < this.rank[yRoot]) {
            this.parent[xRoot] = yRoot;
        } else {
            this.parent[yRoot] = xRoot;
            if (this.rank[xRoot] === this.rank[yRoot]) {
                this.rank[xRoot]++;
            }
        }
    }
}

